export const checkId = 'cors';
export const name = 'CORS Configured';
export const appliesTo = ['deployable', 'server', 'framework'];

const CORS_PATTERNS = [
  /require\s*\(\s*['"][^'"]*cors['"]\s*\)/,
  /import\s+.*?['"][^'"]*cors['"]/,
  /from\s+['"][^'"]*cors['"]/,
  /access-control-allow-origin/i,
  /access-control-allow-methods/i,
  /access-control-allow-headers/i,
  /access-control-allow-credentials/i,
  /access-control-expose-headers/i,
  /access-control-max-age/i,
  /access-control-request/i,
  /cors\s*:\s*(true|\{)/i,
  /cors\s*\(/i,
  /enableCors/i,
  /allowedOrigins?/i,
  /allowOrigin/i,
  /corsOrigins?/i,
  /use\s*\(\s*cors/i,
  /register\s*\([^)]*cors/i,
  /corsHandler/i,
  /handleCors/i,
  /withCors/i,
  /setHeader\s*\(\s*['"]Access-Control/i,
  /headers\.set\s*\(\s*['"]Access-Control/i,
  /headers\s*\(\s*\)\s*\{[^}]*access-control/i,
  /new\s+NextResponse/i,
  /handleCors\s*\(/i,
  /setResponseHeaders\s*\(/i,
  /"headers"\s*:/i,
  /'headers'\s*:/i,
];

const BACKEND_DEPS = ['express', 'fastify', 'koa', 'hono', 'elysia', 'hapi', 'sails', 'meteor', 'feathers', 'restify', 'polka', 'micro', 'connect', 'restana', '0http', 'nitro', 'h3'];
const CONTENT_FRAMEWORKS = ['next', 'nuxt', 'gatsby', 'astro', 'hexo', 'vuepress', 'vitepress', 'docusaurus', 'eleventy'];

const TEST_DIRS_RX = /(^|\/)(node_modules|\.git|\.next|out|dist|build|coverage|\.tmp|test|tests|__tests__|spec|e2e|cypress|playwright|vitest|jest|benchmark|benchmarks|perf|\.cache|storybook)\//i;
const EXCLUDE_FILE_RX = /\.(test|spec|e2e|cy|stories)\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/i;
const SRC_EXT_RX = /\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/;

const SERVER_IMPORT_PATTERNS = [
  /require\s*\(\s*['"](?:express|fastify|koa|hono|elysia|hapi|restify|polka|sails|feathers|restana|connect|nitro|h3)['"]\s*\)/,
  /from\s+['"](?:express|fastify|koa|hono|elysia|hapi|restify|polka|sails|feathers|restana|connect|nitro|h3)['"]/,
  /\.listen\s*\(\s*(?:\d|process\.env|[`'"])/,
  /Deno\.serve\s*\(/,
  /Bun\.serve\s*\(/,
  /http\.createServer\s*\(/,
  /createServer\s*\(/,
  /new\s+(?:Koa|Hono|Fastify|ApolloServer)\s*\(/,
  /export\s+default\s+(?:async\s+)?function\s+handler\b/,
  /export\s+default\s+\{[^}]*async\s+fetch\b/,
  /addEventListener\s*\(\s*['"]fetch['"]/,
  /defineEventHandler\s*\(/,
];

function isTutorial(packageJson) {
  if (!packageJson) return false;
  const text = [
    packageJson.name,
    packageJson.description,
    ...(packageJson.keywords || []),
  ].filter(Boolean).join(' ').toLowerCase();
  return /\b(tutorial|tutorials|course|workshop|learn[- ]?js|learn[- ]?node|getting[- ]?started[- ]?guide|teach[- ]?yourself|courseware|lesson|lessons|walkthrough)\b/.test(text);
}

function isLibraryOrFramework(packageJson, tree, serverEvidence) {
  if (!packageJson) return false;

  if (serverEvidence.hasBackendDep || serverEvidence.hasApiFiles || serverEvidence.hasListenCode) {
    return false;
  }

  const deps = packageJson.dependencies || {};
  if (BACKEND_DEPS.some(d => deps[d])) return false;

  const keywords = (packageJson.keywords || []).map(k => k.toLowerCase());
  const libKeywords = new Set([
    'library', 'framework', 'middleware', 'plugin', 'toolkit', 'sdk',
    'module', 'util', 'utils', 'tool', 'bundler', 'compiler', 'build-tool',
    'router', 'client', 'component', 'components', 'ui', 'functional',
    'helper', 'helpers', 'package', 'transform', 'loader', 'preset',
  ]);
  const hasLibKeyword = keywords.some(k => libKeywords.has(k));

  const hasMain = !!(packageJson.main || packageJson.module || packageJson.exports || packageJson.typings || packageJson.types);
  const hasVersion = !!packageJson.version;
  const hasPeerDeps = !!(packageJson.peerDependencies && Object.keys(packageJson.peerDependencies).length > 0);

  const hasPackagesDir = tree.some(p => /^packages\/[^/]+(?:\/|$)/.test(p));
  const hasAppsDir = tree.some(p => /^(apps|services|clients|web|www|site|sites|server|api|studio|dashboard|admin|portal|frontend|backend|workers|edge-functions)\/[^/]+(?:\/|$)/.test(p));

  if (packageJson.private === true && hasPackagesDir && !hasAppsDir) {
    return true;
  }

  if ((packageJson.workspaces || tree.some(p => /^pnpm-workspace\.yaml$/.test(p))) && !hasAppsDir) {
    return true;
  }

  if (hasMain && hasVersion && (hasLibKeyword || hasPeerDeps)) {
    return true;
  }

  return false;
}

function isStaticContentSite(packageJson, tree, serverEvidence) {
  if (!packageJson) return false;

  if (serverEvidence.hasBackendDep || serverEvidence.hasApiFiles || serverEvidence.hasListenCode) {
    return false;
  }

  const allDeps = { ...(packageJson.dependencies || {}), ...(packageJson.devDependencies || {}) };
  if (BACKEND_DEPS.some(d => allDeps[d])) return false;

  const hasContentFramework = CONTENT_FRAMEWORKS.some(f => allDeps[f]);
  if (!hasContentFramework) return false;

  const contentFiles = tree.filter(p => /\.(md|mdx|html|css|scss|sass|less|styl|svg|png|jpg|jpeg|gif|webp|ico)$/.test(p) && !/(^|\/)node_modules\//.test(p)).length;
  const sourceFiles = tree.filter(p => SRC_EXT_RX.test(p) && !/(^|\/)node_modules\//.test(p)).length;

  if (sourceFiles === 0 && contentFiles > 3) return true;
  if (contentFiles > sourceFiles * 3) return true;

  return true;
}

async function scanSubPackagesForCorsDep(tree, files) {
  const subPkgs = tree.filter(p => /(^|\/)package\.json$/.test(p) && !/(^|\/)node_modules\//.test(p));
  for (const pkgPath of subPkgs.slice(0, 15)) {
    if (pkgPath === 'package.json') continue;
    try {
      const content = await files.get(pkgPath);
      if (!content) continue;
      const subPkg = JSON.parse(content);
      const deps = {
        ...(subPkg.dependencies || {}),
        ...(subPkg.devDependencies || {}),
        ...(subPkg.peerDependencies || {}),
      };
      if (deps.cors || deps['koa-cors']) {
        return pkgPath;
      }
    } catch {
      // ignore invalid JSON
    }
  }
  return null;
}

async function scanFilesForCors(tree, files) {
  const candidates = [];

  for (const p of tree) {
    if (/(^|\/)node_modules\//.test(p)) continue;
    if (TEST_DIRS_RX.test(p)) continue;
    if (EXCLUDE_FILE_RX.test(p)) continue;

    let score = 0;
    const basename = p.split('/').pop() || '';

    if (/\.config\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) score += 100;
    if (/^(vercel\.json|netlify\.toml|_headers|wrangler\.toml|fly\.toml|render\.yaml)$/.test(p)) score += 100;
    if (/^next\.config\.|nuxt\.config\.|astro\.config\.|nitro\.config\./.test(basename)) score += 100;
    if (/^middleware\.(js|ts|mjs|cjs|mts|cts)$/.test(basename)) score += 90;

    if (/(^|\/)api\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) score += 80;
    if (/(^|\/)pages\/api\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) score += 80;
    if (/(^|\/)app\/api\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) score += 80;

    if (/^(src\/)?(server|app|listen|index|main|worker|gateway|api)\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) score += 70;
    if (/(^|\/)server\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) score += 60;
    if (/(^|\/)backend\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) score += 60;
    if (/(^|\/)routes\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) score += 50;
    if (/(^|\/)controllers\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) score += 50;
    if (/(^|\/)handlers\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) score += 50;

    if (SRC_EXT_RX.test(p)) score += 5;

    if (score > 0) candidates.push({ path: p, score });
  }

  candidates.sort((a, b) => b.score - a.score);

  for (const { path } of candidates.slice(0, 20)) {
    try {
      const content = await files.get(path);
      if (!content) continue;
      for (const pat of CORS_PATTERNS) {
        if (pat.test(content)) {
          return path;
        }
      }
    } catch {
      // ignore read errors
    }
  }

  return null;
}

async function gatherServerEvidence(tree, files, packageJson) {
  const evidence = {
    hasBackendDep: false,
    hasApiFiles: false,
    hasListenCode: false,
    hasServerEntry: false,
    hasSubPackageServer: false,
    isServer: false,
    primaryFile: null,
  };

  const allDeps = { ...(packageJson?.dependencies || {}), ...(packageJson?.peerDependencies || {}) };
  if (BACKEND_DEPS.some(d => allDeps[d])) {
    evidence.hasBackendDep = true;
    evidence.isServer = true;
  }

  const candidates = [];

  for (const p of tree) {
    if (/(^|\/)node_modules\//.test(p)) continue;
    if (TEST_DIRS_RX.test(p)) continue;
    if (EXCLUDE_FILE_RX.test(p)) continue;

    let score = 0;

    if (/(^|\/)api\/[^/]+\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/.test(p)) {
      evidence.hasApiFiles = true;
      evidence.isServer = true;
      score += 90;
    } else if (/(^|\/)pages\/api\/[^/]+\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/.test(p)) {
      evidence.hasApiFiles = true;
      evidence.isServer = true;
      score += 90;
    } else if (/(^|\/)app\/api\/[^/]+\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/.test(p)) {
      evidence.hasApiFiles = true;
      evidence.isServer = true;
      score += 90;
    } else if (/(^|\/)server\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) {
      evidence.isServer = true;
      score += 80;
    } else if (/(^|\/)backend\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) {
      evidence.isServer = true;
      score += 80;
    } else if (/(^|\/)routes\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) {
      evidence.isServer = true;
      score += 60;
    } else if (/(^|\/)controllers\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) {
      evidence.isServer = true;
      score += 60;
    } else if (/(^|\/)handlers\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) {
      evidence.isServer = true;
      score += 60;
    } else if (/(^|\/)endpoints\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) {
      evidence.isServer = true;
      score += 60;
    } else if (/(^|\/)middleware\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) {
      evidence.isServer = true;
      score += 50;
    }

    if (/^(src\/)?(server|app|listen|index|main|worker|gateway|api)\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) {
      evidence.hasServerEntry = true;
      score += 100;
    }
    if (/(^|\/)bin\/www$/.test(p)) {
      evidence.hasServerEntry = true;
      score += 100;
    }

    if (SRC_EXT_RX.test(p) && score === 0) {
      score += 5;
    }

    if (score > 0) candidates.push({ path: p, score });
  }

  if (!evidence.isServer) {
    const subPkgs = tree.filter(p => /(^|\/)package\.json$/.test(p) && !/(^|\/)node_modules\//.test(p));
    for (const pkgPath of subPkgs.slice(0, 15)) {
      if (pkgPath === 'package.json') continue;
      try {
        const content = await files.get(pkgPath);
        if (!content) continue;
        const subPkg = JSON.parse(content);
        const subDeps = { ...(subPkg.dependencies || {}), ...(subPkg.peerDependencies || {}) };
        if (BACKEND_DEPS.some(d => subDeps[d])) {
          evidence.hasSubPackageServer = true;
          evidence.isServer = true;
          break;
        }
      } catch {
        // ignore
      }
    }
  }

  candidates.sort((a, b) => b.score - a.score);

  if (evidence.isServer || candidates.length > 0) {
    const toRead = candidates.slice(0, 15);
    for (const { path } of toRead) {
      try {
        const content = await files.get(path);
        if (!content) continue;
        for (const rx of SERVER_IMPORT_PATTERNS) {
          if (rx.test(content)) {
            evidence.hasListenCode = true;
            evidence.isServer = true;
            if (!evidence.primaryFile) evidence.primaryFile = path;
            break;
          }
        }
        if (evidence.hasListenCode) break;
      } catch {
        // ignore
      }
    }
  }

  return evidence;
}

export async function check(context) {
  const { tree, files, packageJson } = context;

  try {
    if (!tree || tree.length === 0) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repository', findings: [] };
    }

    const rootDeps = {
      ...(packageJson?.dependencies || {}),
      ...(packageJson?.devDependencies || {}),
      ...(packageJson?.peerDependencies || {}),
    };
    if (rootDeps.cors || rootDeps['koa-cors']) {
      return { checkId, status: 'pass', confidence: 'high', message: 'CORS dependency found in package.json', findings: [] };
    }

    const subPkgCors = await scanSubPackagesForCorsDep(tree, files);
    if (subPkgCors) {
      return { checkId, status: 'pass', confidence: 'high', message: `CORS dependency found in ${subPkgCors}`, findings: [{ file: subPkgCors, issue: 'cors dependency detected' }] };
    }

    const corsFile = await scanFilesForCors(tree, files);
    if (corsFile) {
      return { checkId, status: 'pass', confidence: 'high', message: `CORS configuration found in ${corsFile}`, findings: [{ file: corsFile, issue: 'CORS detected' }] };
    }

    const serverEvidence = await gatherServerEvidence(tree, files, packageJson);

    if (isLibraryOrFramework(packageJson, tree, serverEvidence)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library or framework source — CORS not applicable', findings: [] };
    }

    if (isStaticContentSite(packageJson, tree, serverEvidence)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Static or content site without API endpoints — CORS not needed', findings: [] };
    }

    if (isTutorial(packageJson) && !serverEvidence.hasBackendDep && !serverEvidence.hasApiFiles && !serverEvidence.hasListenCode) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Tutorial or example repository — CORS not applicable', findings: [] };
    }

    const hasFullstackDep = CONTENT_FRAMEWORKS.some(f => rootDeps[f]);
    if (hasFullstackDep && !serverEvidence.hasApiFiles && !serverEvidence.hasBackendDep && !serverEvidence.hasListenCode) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Fullstack framework site without API routes — CORS not needed', findings: [] };
    }

    if (!serverEvidence.isServer) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'No server or API endpoints detected — CORS not needed', findings: [] };
    }

    return {
      checkId,
      status: 'check-it',
      confidence: 'medium',
      message: 'Backend server detected without visible CORS configuration',
      findings: [{ file: serverEvidence.primaryFile || 'unknown', issue: 'Verify CORS is configured for this API service' }],
    };
  } catch (err) {
    console.error(`[${checkId}] Unexpected error:`, err);
    return { checkId, status: 'not-applicable', confidence: 'high', message: `Error during CORS check: ${err.message}`, findings: [{ file: 'unknown', issue: `Error: ${err.message}` }] };
  }
}
